class Solution {
    public int[] smallestTrimmedNumbers(String[] nums, int[][] queries) {
        int n = nums.length;
        int m = nums[0].length();
        int[] ans = new int[queries.length];
        String[] originalNums = new String[n];
        for (int i = 0; i < n; i++) {
            originalNums[i] = nums[i];
        }

        Arrays.sort(originalNums, (a, b) -> {
            int minLen = Math.min(a.length(), b.length());
            for (int i = 0; i < minLen; i++) {
                if (a.charAt(i) != b.charAt(i)) {
                    return a.charAt(i) - b.charAt(i);
                }
            }
            return a.length() - b.length();
        });

        for (int i = 0; i < queries.length; i++) {
            int k = queries[i][0] - 1;
            int trim = queries[i][1];

            String[] trimmedNums = new String[n];
            for (int j = 0; j < n; j++) {
                trimmedNums[j] = originalNums[j].substring(originalNums[j].length() - trim);
            }

            Arrays.sort(trimmedNums, (a, b) -> {
                int minLen = Math.min(a.length(), b.length());
                for (int j = 0; j < minLen; j++) {
                    if (a.charAt(j) != b.charAt(j)) {
                        return a.charAt(j) - b.charAt(j);
                    }
                }
                return a.length() - b.length();
            });

            for (int j = 0; j < n; j++) {
                if (trimmedNums[j].equals(originalNums[j].substring(originalNums[j].length() - trim))) {
                    ans[i] = j;
                    break;
                }
            }
        }
        return ans;
    }
}
